SELECT * FROM replies
WHERE comment_id = #{commentId}
AND status = 'NORMAL'
ORDER BY created_at ASC
LIMIT #{offset}, #{size}

SELECT r.* FROM replies r WHERE r.status = 'NORMAL' AND r.comment_id IN
#{commentId}
AND ( SELECT COUNT(*) FROM replies r2 WHERE r2.comment_id = r.comment_id AND r2.status = 'NORMAL' AND ( r2.created_at < r.created_at OR (r2.created_at = r.created_at AND r2.id <= r.id) ) ) <= #{limitPerComment} ORDER BY r.comment_id ASC, r.created_at ASC, r.id ASC

SELECT COUNT(*) FROM replies
WHERE comment_id = #{commentId}
AND status = 'NORMAL'

SELECT r.* FROM replies r
INNER JOIN comments c ON r.comment_id = c.id
INNER JOIN manuscripts m ON c.manuscript_id = m.id
WHERE m.user_id = #{userId}

    AND c.manuscript_id = #{manuscriptId}

AND r.status = 'NORMAL'


        ORDER BY r.like_count DESC, r.created_at DESC


        ORDER BY r.created_at DESC


LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM replies r
INNER JOIN comments c ON r.comment_id = c.id
INNER JOIN manuscripts m ON c.manuscript_id = m.id
WHERE m.user_id = #{userId}

    AND c.manuscript_id = #{manuscriptId}

AND r.status = 'NORMAL'
